beginning.embedded_functions:
//each function name should be prefixed by em_
/**
* Return:
* - 0: ok
* - 1: invalid
* - 2: NULL
*/
static inline int em_check_fuzzing(const char *payload, int payload_length) {
    if (!payload) {
        return 0; // Handle NULL payload gracefully
    }

    for (int i = 0; i < payload_length; i++) {
        if (payload[i] == '\\' || payload[i] == '#' || payload[i] == '%' || payload[i] == '$') {
            return 1; // Found a suspicious character
        }
    }
    return 0; // No suspicious characters found
}
